	.TITLE	FLIPPER	.PROC	Z80	.REF	FLO	.LOC	60000; Dfinitions:; ------------G	=	6.		; attractionMAXVY	=	11.		; vitesse maximale en YMINVY	=	0		; vitesse minimale en YMAXVX	=	10.		; vitesse maximale en XMINVX	=	0		; vitesse minimale en XMINX	=	0		; rectangle de jeuMINY	=	0MAXX	=	130.MAXY	=	120.-1RESTC	=	(MAXX-MINX-10.-2*15.)/2  ; reste en basMILX	=	(MAXX-MINX)/2	; milieu du jeu en XCOORRG	=	400*(106.)+(MINX+42.)COORRD	=	400*(106.)+(MAXX-42.-16.)ORPAYE	=	69.*400+205.	; origine du film "paye"ORLOT	=	44.*400+207.	; origine loterieTXLOT	=	11.*400+52.	; origine texte loterieCGI1Y	=	39.CGI2Y	=	45.CGI3Y	=	63.CGI1X	=	56.CGI2X	=	84.CGI3X	=	64.COOGI1	=	400*CGI1Y+CGI1XCOOGI2	=	400*CGI2Y+CGI2XCOOGI3	=	400*CGI3Y+CGI3XCPI1Y	=	16.CPI2Y	=	19.CPI3Y	=	22.CPI1X	=	54.CPI2X	=	69.CPI3X	=	84.COOPI1	=	400*CPI1Y+CPI1XCOOPI2	=	400*CPI2Y+CPI2XCOOPI3	=	400*CPI3Y+CPI3XDELRAQ	=	10.		; dlai d'effet des raquettes;20LGBOUCH	=	50.*15.		; temps du bouchon (15 sec)LGPROT	=	50.*30.		; temps des protectionsFLASH	=	50./10.		; temps des "flashs"ADSTOP	=	SALPHA+NCAR*16.+14.  ; adresse message "stop"ADEXTRA	=	SALPHA+NCAR*14.+11.  ; adresse message "extra ball"ADXN	=	SALPHA+NCAR*8.+15.   ; adresse message " X N "ADCIB1	=	SALPHA+NCAR*7.+3.    ; adresse cible gaucheADCIB2	=	SALPHA+NCAR*6.+29.   ; adresse cible droiteADPRO1	=	SALPHA+NCAR*2.+11.ADPRO2	=	SALPHA+NCAR*2.+15.ADPRO3	=	SALPHA+NCAR*3.+19.NBBAL	=	5.		; nombre de boule par partieLGRATI	=	9990.		; premire partie gratuiteIGRATI	=	2000.		; inc pour partie grat. suiv.POINT	=	42564		; location systme !; Programme:; ----------START:	LOAD	SVSP,SP	LOAD	C,#LINES	.W	?IDIS	XOR	A,A	LOAD	PARTIE,AREPAYE:	CALL	FILM		; p'tit film du dbutRECOMMENCE:	XOR	A,A	LOAD	NBJ,A	.W	?CLEAR,?CGRA	LOAD	DE,#400*10.+200.	LOAD	BC,#0	CALL	GFLIPPER	LOAD	DE,#400*30.+200.	LOAD	BC,#0	CALL	GSMAKY	.W	?TEXTIM.B	CR,CR.ASCII /(CURSOR)	--> flipper gauche<CR>/.ASCII /(CHANGE)	--> flipper droite<CR>/.ASCII /(RETURN)	--> lance la boule<CR>/.B	CR.ASCII	/(P)		--> paye la machine<CR>/.ASCII	/(S)		--> Slectionne<CR>/.ASCII	/(J)		--> Lance le jeu<CR>/.B	CR.ASCII	/1re PARTIE GRATUITE /.B	0	LOAD	HL,#LGRATI	.W	?BINBCD	.W	?AFXHL	.W	?TEXTIM	.ASCIZ	/ POINTS, LES SUIVANTES +/	LOAD	HL,#IGRATI	.W	?BINBCD	.W	?AFXHL	.W	?TEXTIM	.ASCIZ	/ POINTS/60$:	LOAD	HL,#400*12.+0	.W	?SETCURS,?TEXTIM	.ASCIZ	/Nombre de joueur(s): /	LOAD	A,NBJ	ADD	A,#'0	.W	?DICAR,?TEXTIM	.ASCIZ	/<CR><CR>Partie(s): /	LOAD	A,PARTIE	LOAD	L,A	LOAD	H,#0	.W	?BINBCD	LOAD	A,L	.W	?AFHEX	LOAD	HL,#400*17.+0	.W	?SETCURS	.W	?TEXTIM.ASCIZ	/<INV> PAYEZ, SELECTIONNEZ ET JOUEZ ! <NORM>/65$:	CALL	CLRCAR		; vide le fifo du clavier66$:	CALL	IFCAR	JUMP,CS	66$70$:	COMP	A,#END	JUMP,EQ	RETOUR	CLR	A:5	COMP	A,#'J	JUMP,EQ	80$	COMP	A,#'S	JUMP,EQ	75$	COMP	A,#'P	JUMP,NE	65$	LOAD	A,PARTIE	COMP	A,#99.	JUMP,EQ	65$	INC	A	LOAD	PARTIE,A	LOAD	HL,#400*17.+0	.W	?SETCURS	.W	?SPACE,?SETCURS,?EFLI	CALL	FIPAYE	JUMP	60$75$:	LOAD	A,PARTIE	OR	A,A	JUMP,EQ 65$	DEC	A	LOAD	PARTIE,A	LOAD	HL,#400*17.+0	.W	?SETCURS	.W	?SPACE,?SETCURS,?EFLI	LOAD	C,#10.76$:	PUSH	BC	DECJ,NE	B,.	LOAD	HL,#B6	CALL	BRUIT	POP	BC	DEC	C	JUMP,NE	76$	LOAD	A,NBJ	INC	A	LOAD	NBJ,A	COMP	A,#4	JUMP,EQ	85$	JUMP	60$80$:	LOAD	A,NBJ	OR	A,A	JUMP,EQ	65$85$:	XOR	A,A	LOAD	NOJ,A	LOAD	HL,#TACNT	LOAD	B,#(ETACNT-TACNT)/8.10$:	LOAD	(HL),#0	INC	HL	LOAD	(HL),#0	INC	HL	LOAD	(HL),#0	INC	HL	LOAD	(HL),#0	INC	HL	INC	HL	INC	HL	INC	HL	INC	HL	DECJ,NE	B,10$	LOAD	HL,#TAFLASH	LOAD	B,#(ETAFLASH-TAFLASH)/3.20$:	LOAD	(HL),#0	INC	HL	INC	HL	INC	HL	DECJ,NE	B,20$	.IF	COBUS	LOAD	HL,#RETOUR	.W	?IADNMI	.ENDIF	.W	?CALPHA	CALL	INICNT		; init les 4 compteurs	XOR	A,A	LOAD	EXTRA,A	LOAD	A,#NBBAL	LOAD	CNTBAL,A	JUMP	REST0RESTART:	LOAD	SP,SVSP	LOAD	A,EXTRA	OR	A,A	JUMP,NE	REST0	LOAD	A,NBJ	LOAD	C,A		; C  <-- nb de joueurs	DEC	C	LOAD	A,NOJ		; passe au joueur suivant	COMP	A,C		; retour au 1er joueur ?	JUMP,NE	20$		; oui =>	LOAD	A,CNTBAL	DEC	A	JUMP,EQ	FINI	LOAD	CNTBAL,A	; une partie en moins	LOAD	A,#-120$:	INC	A	LOAD	NOJ,AREST0:	LOAD	C,#NLI	.W	?IDIS		; "cache" l'cran graphique	.W	?CGRA	LOAD	IX,#DESTAC	CALL	CONTA		; dessine le terrain de jeu	LOAD	IX,#GILOT	LOAD	DE,#COOGI1	CALL	CONTRE	LOAD	IX,#GILOT	LOAD	DE,#COOGI2	CALL	CONTRE	LOAD	IX,#GILOT	LOAD	DE,#COOGI3	CALL	CONTRE	LOAD	IX,#PILOT	LOAD	DE,#COOPI1	CALL	CONTRE	LOAD	IX,#PILOT	LOAD	DE,#COOPI2	CALL	CONTRE	LOAD	IX,#PILOT	LOAD	DE,#COOPI3	CALL	CONTRE	CALL	INIRAQ		; dessine les raquettes	CALL	FLIPPER		; affiche "Flipper..."	XOR	A,A	LOAD	STAEFF,A	; init effet maximal  zro	LOAD	A,NOJ	CALL	GETCNT		; IX <-- ^compteur	LOAD	L,(IX)+4	LOAD	H,(IX)+5	LOAD	POINT,HL	.W	?GETCURS,?ALGRA	LOAD	IX,#CADRE	CALL	CONTRE		; dessine cadre du compteur	LOAD	C,#NLI	.W	?IDIS	OR	A,A		; gros points	.W	?IAGRA		; montre le graphique	.W	?TEXTIM	.B	CR,CR,CR,CR,CR,CR	.ASCII	/             10<CR>/	.ASCII	/                    10<CR>/	.B	CR,CR	.ASCII	/               20<CR>/	.B	0	LOAD	HL,#400*17.+47.	.W	?SETCURS,?TEXTIM	.ASCIZ	/Parties: /	LOAD	A,PARTIE	LOAD	L,A	LOAD	H,#0	.W	?BINBCD	LOAD	A,L	.W	?AFHEX	LOAD	HL,#400*19.+47.	.W	?SETCURS,?TEXTIM	.ASCIZ	/Boule en jeu: /	LOAD	A,CNTBAL	LOAD	L,A	LOAD	A,#NBBAL+1	SUB	A,L	LOAD	L,A	LOAD	H,#0	.W	?BINBCD	LOAD	A,L	.W	?AFHEX	CALL	AFFCNT		; affiche tous les compteurs	LOAD	A,#'*		; place les "cibles"	LOAD	ADCIB1,A	LOAD	ADCIB2,A	LOAD	A,#'o		; place les protections	LOAD	ADPRO1,A	LOAD	ADPRO2,A	LOAD	ADPRO3,A	LOAD	A,EXTRA	OR	A,A	JUMP,EQ	10$	LOAD	HL,#ADEXTRA	INC	HL	INC	HL	LOAD	(HL),#'R	INC	HL	LOAD	(HL),#'E	INC	HL	LOAD	(HL),#'J	INC	HL	LOAD	(HL),#'O	INC	HL	LOAD	(HL),#'U	INC	HL	LOAD	(HL),#'E10$:	CALL	LANCE		; lance la balle ...	XOR	A,A	LOAD	CPXN,A	LOAD	A,#1	LOAD	EXTRA,A		; TEST SI 0 POINTS	LOAD	HL,#ADEXTRA	LOAD	B,#6	INC	HL	INC	HL20$:	LOAD	(HL),#SPACE	INC	HL	DECJ,NE	B,20$	LOAD	A,#G	LOAD	CNTP,A	XOR	A,A	LOAD	CNTCIB,A	LOAD	CNTIL1,A	LOAD	CNTIL2,A	LOAD	CNTIL3,A	LOAD	HL,#0	LOAD	CNTBOU,HL	LOAD	CNTPRO,HL	LOAD	HL,#CLOCK50	.W	?IRTC		; enclanche la RTC	LOAD	HL,MDELX	LOAD	DELX,HL	LOAD	HL,MDELY	LOAD	DELY,HLLOOP:	.W	?GETFONC	LOAD	FONC,A		; FONC <-- touches fonctions	LOAD	C,#0	LOAD	HL,DELX	DEC	HL	LOAD	DELX,HL	LOAD	A,L	OR	A,H	JUMP,NE	20$	SET	C:0	LOAD	HL,MDELX	LOAD	DELX,HL		; DELX <-- MDELX	LOAD	A,SENSX	LOAD	B,A	LOAD	A,BALX	ADD	A,B	LOAD	BALX,A		; BALX <-- BALX + SENSX20$:	LOAD	HL,DELY	DEC	HL	LOAD	DELY,HL	LOAD	A,L	OR	A,H	JUMP,NE	40$	SET	C:0	LOAD	HL,MDELY	LOAD	DELY,HL		; DELY <-- MDELY	LOAD	A,SENSY	LOAD	B,A	LOAD	A,BALY	ADD	A,B	LOAD	BALY,A		; BALY <-- BALY + SENSY40$:	TEST	C:0	JUMP,EQ	LOOPIOF ;---------------------------;	LOAD	DE,BAL	CALL	BALLE		; dessine nouvelle balle	LOAD	DE,OBAL	CALL	BALLE		; enlve ancienne balle	LOAD	DE,BAL	LOAD	OBAL,DEION ;---------------------------;	LOAD	DE,BAL	CALL	RADAR		; obstacle touch ?	CALL	CHADIR		; oui => change de direction	CALL	EFFETS	LOAD	IX,#TZONES	CALL	EFFET0	JUMP	LOOPPERDU:	CALL	BBLANC		; fait un drle de bruit blanc10$:	.W	?DELAY,1000./4	LOAD	A,#25	.W	?BEEP		; tut ...	LOAD	A,NOJ	CALL	GETCNT	TEST	(IX)+6:2	; compteur  jour ?	JUMP,EQ	10$		; oui => 20$20$:	CALL	AFFCNT		; affiche tous les compteurs	LOAD	HL,#0	.W	?IRTC		; plus de RTC ...	CALL	ADDEFF		; ajoute les effets spciaux	LOAD	A,EXTRA	OR	A,A	JUMP,NE	40$	LOAD	A,CNTBAL	DEC	A	CALL,EQ LOTERI40$:	SETC	.W	?IAGRA		; p'tits points + alpha	LOAD	C,#20.50$:	DECJ,NE	B,.	PUSH	BC	CALL	FLIPPER		; fait clignotter "Flipper..."	LOAD	HL,#B6	CALL	BRUIT	POP	BC	DEC	C	JUMP,NE	50$	JUMP	RESTARTFINI:	LOAD	HL,#0	.W	?IRTC	LOAD	A,NOJ	CALL	GETCNT	LOAD	L,(IX)+4	LOAD	H,(IX)+5	LOAD	POINT,HL	.W	?GETCURS,?ALGRA	LOAD	IX,#ECADRE	; efface le cadre du dernier	CALL	CONTRE		; joueur	LOAD	A,NBJ	LOAD	B,A	LOAD	C,#0	LOAD	HL,#0		; HL <-- nb de pts maximum10$:	LOAD	A,C	CALL	GETCNT	LOAD	E,(IX)+0	LOAD	D,(IX)+1	.W	?COMPHLDE	JUMP,HS	20$	EX	HL,DE		; HL <-- nb max20$:	INC	C	DECJ,NE	B,10$	LOAD	A,NBJ	LOAD	B,A	LOAD	C,#0	LOAD	IY,#TACADRES30$:	LOAD	A,C	CALL	GETCNT	LOAD	E,(IX)+0	LOAD	D,(IX)+1	.W	?COMPHLDE	JUMP,NE	40$	PUSH	HL	LOAD	L,(IX)+4	LOAD	H,(IX)+5	LOAD	POINT,HL	.W	?GETCURS,?ALGRA	LOAD	(IY)+0,E	LOAD	(IY)+1,D	INC	IY	INC	IY	POP	HL40$:	INC	C	DECJ,NE	B,30$	LOAD	(IY)+0,#0	LOAD	(IY)+1,#0	CALL	AFFCNT		; affiche tous les compteurs	OR	A,A	.W	?IAGRA50$:	LOAD	IY,#TACADRES60$:	LOAD	E,(IY)+0	LOAD	D,(IY)+1	INC	IY	INC	IY	LOAD	A,E	OR	A,D	JUMP,EQ	65$	LOAD	IX,#CADRE	CALL	CONTRE		; dessine cadre d'un compteur	JUMP	60$65$:	LOAD	HL,#B11	CALL	BRUIT	.W	?DELAY,1000./4.	LOAD	IY,#TACADRES80$:	LOAD	E,(IY)+0	LOAD	D,(IY)+1	INC	IY	INC	IY	LOAD	A,E	OR	A,D	JUMP,EQ	85$	LOAD	IX,#ECADRE	CALL	CONTRE		; efface cadre d'un compteur	JUMP	80$85$:	LOAD	HL,#B2	CALL	BRUIT	.W	?DELAY,1000./8.	CALL	IFCAR	JUMP,CS	50$	COMP	A,#END	JUMP,EQ	RETOUR	LOAD	A,PARTIE	OR	A,A	JUMP,NE	RECOMMENCE	JUMP	REPAYERETOUR:	LOAD	C,#NLI	.W	?IDIS	.IF	COBUS	.W	?RTN	.ELSE	TRAP	.ENDIF;--------\; ADDEFF  >;========/ADDEFF:	LOAD	A,STAEFF	TEST	A:0	JUMP,EQ	20$	LOAD	B,#11.10$:	PUSH	BC	.W	?DELAY,100.	CALL	AF10	LOAD	HL,#B2	CALL	BRUIT	POP	BC	DECJ,NE	B,10$	LOAD	A,NOJ	CALL	GETCNT	LOAD	L,(IX)+0	LOAD	H,(IX)+1	LOAD	DE,#10.	ADD	HL,DE	LOAD	(IX)+0,L	LOAD	(IX)+1,H	CALL	GRATIS	CALL	AFFCNT	LOAD	HL,#B6	CALL	BRUIT20$:	LOAD	A,STAEFF	TEST	A:1	JUMP,EQ	40$	LOAD	B,#11.30$:	PUSH	BC	.W	?DELAY,100.	CALL	AF20	LOAD	HL,#B2	CALL	BRUIT	POP	BC	DECJ,NE	B,30$	LOAD	A,NOJ	CALL	GETCNT	LOAD	L,(IX)+0	LOAD	H,(IX)+1	LOAD	DE,#20.	ADD	HL,DE	LOAD	(IX)+0,L	LOAD	(IX)+1,H	CALL	GRATIS	CALL	AFFCNT	LOAD	HL,#B6	CALL	BRUIT40$:	LOAD	A,STAEFF	TEST	A:2	JUMP,EQ	60$	LOAD	B,#11.50$:	PUSH	BC	.W	?DELAY,100.	CALL	AF50	LOAD	HL,#B2	CALL	BRUIT	POP	BC	DECJ,NE	B,50$	LOAD	A,NOJ	CALL	GETCNT	LOAD	L,(IX)+0	LOAD	H,(IX)+1	LOAD	DE,#50.	ADD	HL,DE	LOAD	(IX)+0,L	LOAD	(IX)+1,H	CALL	GRATIS	CALL	AFFCNT	LOAD	HL,#B6	CALL	BRUIT60$:	LOAD	A,STAEFF	TEST	A:3	JUMP,EQ	80$	LOAD	B,#21.70$:	PUSH	BC	.W	?DELAY,100.	CALL	AF100	LOAD	HL,#B2	CALL	BRUIT	POP	BC	DECJ,NE	B,70$	LOAD	A,NOJ	CALL	GETCNT	LOAD	L,(IX)+0	LOAD	H,(IX)+1	LOAD	DE,#100.	ADD	HL,DE	LOAD	(IX)+0,L	LOAD	(IX)+1,H	CALL	GRATIS	CALL	AFFCNT	LOAD	HL,#B6	CALL	BRUIT80$:	RET;--------\; LANCE   >;========/; Lance la balle.LANCE:	LOAD	D,#MAXY-10.	LOAD	E,#MAXX+5.	CALL	BALLE		; dessine toute 1re balle	CALL	GETCAR		; attend une touche quelconque	COMP	A,#END	JUMP,EQ	FINI	COMP	A,#SEND	JUMP,EQ	RETOUR	LOAD	B,#85.50$:	LOAD	A,#5.51$:	LOAD	C,B	INC	C52$:	DEC	C	JUMP,NE	52$	LOAD	$HP,A	DEC	A	JUMP,NE	51$	DEC	D	CALL	BALLE		; dessine nouvelle balle	INC	D	CALL	BALLE		; supprime ancienne balle	DEC	D	DECJ,NE	B,50$	LOAD	B,#10.60$:	DEC	E	DEC	D	CALL	BALLE		; dessine nouvelle balle	INC	E	INC	D	CALL	BALLE		; supprime ancienne balle	DEC	E	DEC	D	DECJ,NE	B,60$	LOAD	B,#20.70$:	DEC	E	CALL	BALLE		; dessine nouvelle balle	INC	E	CALL	BALLE		; supprime ancienne balle	DEC	E	DECJ,NE	B,70$	LOAD	BAL,DE	LOAD	OBAL,DE	LOAD	A,#1	CALL	CMOD	LOAD	DE,#400*52.+MAXX	LOAD	HL,#400*47.+MAXX+10.	CALL	SEGA		; bouche l'entre !	LOAD	A,#5	CALL	IVITY	LOAD	A,R		; pseudo-alatoire !!!	AND	A,#3	ADD	A,#4	CALL	IVITX	LOAD	A,#-1	LOAD	SENSX,A	LOAD	A,#-1	LOAD	SENSY,A	RET;--------\; CLOCK50 >;========/; Routine d'interuption 50Hz.CLOCK50:	PUSH	IX	PUSH	IY	CALL	PESENTEUR	CALL	BOURAQ	CALL	MAJCNT	CALL	EXFLASH	LOAD	A,CNTCIB	OR	A,A	JUMP,EQ	10$	DEC	A	LOAD	CNTCIB,A	JUMP,NE	10$	LOAD	A,#'*	LOAD	ADCIB1,A	; remet les cibles	LOAD	ADCIB2,A10$:	LOAD	HL,CNTBOU	LOAD	A,L	OR	A,H		; bouchon en place ?	JUMP,EQ	50$		; non => 50$	DEC	HL	LOAD	CNTBOU,HL	; attend ...	LOAD	A,L	OR	A,H	JUMP,NE	50$	CALL	AIDEX		; si fini => enlve le	LOAD	HL,#ADSTOP	LOAD	(HL),#SPACE	INC	HL		; efface message "stop"	LOAD	(HL),#SPACE	INC	HL	LOAD	(HL),#SPACE	INC	HL	LOAD	(HL),#SPACE	LOAD	HL,#ADXN	LOAD	(HL),#SPACE	INC	HL	INC	HL	LOAD	(HL),#SPACE	LOAD	HL,#STAEFF	CLR	(HL):750$:	LOAD	HL,CNTPRO	LOAD	A,L		; protection existe ?	OR	A,H	JUMP,EQ	70$		; non => 70$	DEC	HL	LOAD	CNTPRO,HL	LOAD	A,L	OR	A,H	JUMP,NE	70$	CALL	SUPPRO		; supprime la protection	LOAD	HL,#B10	CALL	BRUIT70$:	POP	IY	POP	IX	RET;-----------\; PESENTEUR  >;===========/PESENTEUR:	LOAD	HL,#CNTP	DEC	(HL)	RET,NE	LOAD	(HL),#G	LOAD	A,SENSY	TEST	A:7		; monte ou descend ?	JUMP,NE	50$				; descend (+)	LOAD	A,VITY	COMP	A,#MAXVY	RET,EQ40$:	INC	A		; augmente la vitesse	JUMP	90$50$:				; monte (-)	LOAD	A,VITY	COMP	A,#MINVY	; presque arrt ?	JUMP,NE	80$		; non => 80$				; oui =>	PUSH	AF	LOAD	A,#1	LOAD	SENSY,A		; init sens en descente ...	POP	AF	JUMP	40$80$:	DEC	A		; diminue la vitesse90$:	CALL	IVITY	RET;---------\; CHOCBAS  >;=========/CHOCBAS:	PUSH	DE	PUSH	HL	LOAD	A,VITY	LOAD	E,A	LOAD	D,#0	LOAD	HL,#50$	ADD	HL,DE	LOAD	A,(HL)		; A  <-- vitesse amortie	CALL	IVITY	POP	HL	POP	DE	RET; Table des vitesse amortie lors d'un choc  plat:50$:	.B	0		; 0	.B	0		; 1	.B	0		; 2	.B	1		; 3	.B	1		; 4	.B	2		; 5	.B	3		; 6	.B	4		; 7	.B	5		; 8	.B	6		; 9	.B	7		; 10;---------\; CHOCHOR  >;=========/CHOCHOR:	PUSH	DE	PUSH	HL	LOAD	A,VITX	LOAD	E,A	LOAD	D,#0	LOAD	HL,#50$	ADD	HL,DE	LOAD	A,(HL)		; A  <-- vitesse amortie	CALL	IVITX	POP	HL	POP	DE	RET; Table des vitesse amortie lors d'un choc horizontal:50$:	.B	0		; 0	.B	1		; 1	.B	2		; 2	.B	2		; 3	.B	3		; 4	.B	4		; 5	.B	5		; 6	.B	6		; 7	.B	7		; 8	.B	8.		; 9	.B	9.		; 10;--------\; CHOCRAQ >;========/; in	BALX	position horizontale; out	VITX;	VITY; mod	AFCHOCRAQ:	PUSH	DE	PUSH	HL	LOAD	A,BALX	LOAD	E,A	LOAD	D,#0	LOAD	HL,#50$	ADD	HL,DE	LOAD	A,VITY	ADD	A,(HL);	LOAD	A,(HL)		; A  <-- vitesse de dpart	CALL	IVITY	LOAD	A,#-1	LOAD	SENSY,A	LOAD	A,BALX	LOAD	E,A	LOAD	D,#0	LOAD	HL,#60$	ADD	HL,DE	LOAD	A,VITX	ADD	A,(HL);	LOAD	A,(HL)		; A  <-- vitesse de dpart	LOAD	D,#1	TEST	A:7	JUMP,EQ	30$	LOAD	D,#-1	NEG	A30$:	CALL	IVITX	LOAD	A,D	LOAD	SENSX,A	POP	HL	POP	DE	RET50$:				; vitesse de dpart en Y	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 10	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 20	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 30	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 40	.B	0	.B	3	;*	.B	4	.B	5	.B	6	.B	7	.B	8.	.B	9.	.B	10.	.B	10.		; 50	.B	10.	.B	10.	.B	11.	.B	11.	.B	11.	.B	11.	.B	11.	.B	11.	;*	.B	11.	.B	11.		; 60	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	11.		; 70	.B	11.	.B	11.	;*	.B	11.	.B	11.	.B	11.	.B	11.	.B	11.	.B	10.	.B	10.	.B	10.		; 80	.B	10.	.B	9.	.B	8.	.B	7	.B	6	.B	5	.B	4	.B	3	;*	.B	0	.B	0		; 90	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	060$:				; vitesse de dpart en X	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 10	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 20	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 30	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0		; 40	.B	0	.B	-4	;*	.B	-3	.B	-2	.B	-1	.B	0	.B	1	.B	2	.B	3	.B	4		; 50	.B	5	.B	6	.B	7	.B	8.	.B	9.	.B	10.	.B	10.	.B	10.	;*	.B	10.	.B	10.		; 60	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	-10.		; 70	.B	-10.	.B	-10.	;*	.B	-10.	.B	-10.	.B	-9.	.B	-8.	.B	-7	.B	-6	.B	-5	.B	-4		; 80	.B	-3	.B	-2	.B	-1	.B	0	.B	1	.B	2	.B	3	.B	4	;*	.B	0	.B	0		; 90	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0	.B	0;--------\; EXFLASH >;========/; Efface les motifs "flashs" qui ont t affichs assez; longtemps.EXFLASH:	LOAD	IX,#TAFLASH-3	; traite tout	LOAD	A,STAEFF	OR	A,A	JUMP,SC	10$	LOAD	IX,#PTAFLASH-3	; ne traite pas les lots10$:	INC	IX	INC	IX	INC	IX		; IX <-- ^suivant	LOAD	A,(IX)	INC	A		; fin table ?	RET,EQ			; oui => retour	DEC	A		; motif dessin actuellement ?	JUMP,EQ	10$		; non => 10$ (zro)	DEC	(IX)		; oui => attend un p'tit peu	JUMP,NE	10$		; temps fini ?	LOAD	HL,#10$		; oui =>	PUSH	HL		; efface le motif	LOAD	L,(IX)+1	LOAD	H,(IX)+2	JUMP	(HL); Gestion de la balle:; --------------------;--------\; BALLE   >;========/; Dessine ou efface une balle.; in	DE	coordonne balle; out	-; mod	AFBALLE:	DEC	E	CALL	INVP	INC	D	CALL	INVP	INC	E	INC	D	CALL	INVP	INC	E	CALL	INVP	INC	E	DEC	D	CALL	INVP	DEC	D	CALL	INVP	DEC	E	DEC	D	CALL	INVP	DEC	E	CALL	INVP	INC	D	RET;--------\; RADAR   >;========/; Detecte si la balle arrive dans un obstacle quelconque.;	    3 3		C	coordonne de la balle;	3,0 B B 2,3	B	balle;	0 B C   B 2	0..3	bits dans OBSTACLE;	0 B     B 2;	0,1 B B 1,2;	    1 1; in	DE	coordonnes balle; out	A	obstacles ventuels;	OBSTACLE idem; mod	AFRADAR:	PUSH	BC	LOAD	C,#0	DEC	E	DEC	E	CALL	TESTP	JUMP,EQ	10$	SET	C:010$:	INC	D	CALL	TESTP	JUMP,EQ	20$	SET	C:020$:	INC	D	INC	E	CALL	TESTP	JUMP,EQ	30$	SET	C:0	SET	C:130$:	INC	D	INC	E	CALL	TESTP	JUMP,EQ	40$	SET	C:140$:	INC	E	CALL	TESTP	JUMP,EQ	50$	SET	C:150$:	DEC	D	INC	E	CALL	TESTP	JUMP,EQ	60$	SET	C:1	SET	C:260$:	DEC	D	INC	E	CALL	TESTP	JUMP,EQ	70$	SET	C:270$:	DEC	D	CALL	TESTP	JUMP,EQ	80$	SET	C:280$:	DEC	D	DEC	E	CALL	TESTP	JUMP,EQ	90$	SET	C:2	SET	C:390$:	DEC	D	DEC	E	CALL	TESTP	JUMP,EQ	92$	SET	C:392$:	DEC	E	CALL	TESTP	JUMP,EQ	94$	SET	C:394$:	INC	D	DEC	E	CALL	TESTP	JUMP,EQ	96$	SET	C:3	SET	C:096$:	INC	E	INC	D	LOAD	A,C		; A  <-- obstacles	LOAD	OBSTACLE,A	POP	BC	RET;--------\; CHADIR  >;========/; Change la direction de la balle en fonction de l'obstacle; rencontr.; in	OBATACLE;	SENS; out	SENS; mod	AFCHADIR:	PUSH	BC	PUSH	DE	PUSH	HL	LOAD	A,OBSTACLE	OR	A,A		; obstacles existent ?	JUMP,EQ	90$		; non => 90$	LOAD	C,A	LOAD	HL,SENS		; L <-- SENSX  et  H <-- SENSY	LOAD	DE,BAL	TEST	C:0		; touche  gauche ?	JUMP,EQ	10$	LOAD	L,#1	INC	E	CALL	CHOCHOR	CALL	TIC10$:	TEST	C:2		; touche  droite ?	JUMP,EQ	20$	LOAD	L,#-1	DEC	E	CALL	CHOCHOR	CALL	TIC20$:	TEST	C:3		; touche en haut ?	JUMP,EQ	30$	LOAD	H,#1	INC	D	CALL	TIC30$:	TEST	C:1		; touche en bas ?	JUMP,EQ	40$	LOAD	H,#-1	DEC	D	CALL	CHOCBAS		; amorti la balle !	CALL	TIC40$:	LOAD	SENS,HL	LOAD	BAL,DE90$:	POP	HL	POP	DE	POP	BC	RET;--------\; EFFETS  >;========/; Modifie la vitesse de la balle en fonction de l'obstacle; rencontr. Certain obstacles peuvent faire des "effets".; in	DE	coordonne de la balle; out	; mod	toutEFFETS:	LOAD	A,OBSTACLE	OR	A,A		; obstacle rencontr ?	RET,EQ			; non => retour	LOAD	IX,#TEFFETSEFFET0:10$:	LOAD	A,(IX)	COMP	A,#377		; table finie ?	RET,EQ			; oui => retour	LOAD	A,D	COMP	A,(IX)+0	JUMP,LO	20$	COMP	A,(IX)+2	JUMP,HS	20$	LOAD	A,E		; coordonne (DE) dans le	COMP	A,(IX)+1	; rectangle de dlimitation ?	JUMP,LO	20$	COMP	A,(IX)+3	JUMP,HS	20$	LOAD	L,(IX)+4	; oui =>	LOAD	H,(IX)+5	JUMP	(HL)		; excute routine20$:	INC	IX		; non =>	INC	IX	INC	IX	INC	IX	INC	IX	INC	IX		; IX <-- ^lment suivant	JUMP	10$; Organisation de la table TEFFETS:;;    D(x,y);	!-------!;	!	!;	!	!;	!-------!;	      F(x,y);;	.B	D(y)	D(x);	.B	F(y)	F(x);	.W	routineTEFFETS:	.B	MAXY-20.	MINX+42.	; raq. gauche	.B	MAXY		MINX+62.	.W	10$	.B	MAXY-20.	MAXX-62.	; raq. droite	.B	MAXY		MAXX-42.	.W	20$	.B	CGI1Y-10.	CGI1X-11.	; grand ilot	.B	CGI1Y+10.	CGI1X+11.	.W	31$	.B	CGI2Y-10.	CGI2X-11.	; grand ilot	.B	CGI2Y+10.	CGI2X+11.	.W	32$	.B	CGI3Y-10.	CGI3X-11.	; grand ilot	.B	CGI3Y+10.	CGI3X+11.	.W	33$	.B	79.		MINX+25.	; triangle g.	.B	93.		MINX+35.	.W	40$	.B	79.		MAXX-35.	; triangle d.	.B	93.		MAXX-25.	.W	45$	.B	0		MAXX-10.	; super-canon	.B	10.		MAXX+10.	.W	80$	.B	MAXY-5.		MINX		; trou gauche	.B	MAXY		MINX+10.	.W	PERDU	.B	MAXY-5.		MAXX-10.	; trou droite	.B	MAXY		MAXX+10.	.W	PERDU	.B	116.		MINX+40.	; trou milieu	.B	120.		MAXX-40.	.W	PERDU	.B	377		; fin de la table10$:	LOAD	A,STARAQ	TEST	A:1		; raquette gauche leve ?	RET,EQ			; non => retour				; oui =>	LOAD	A,CNTRG	OR	A,A		; leve depuis trop longtemps ?	JUMP,EQ	25$		; oui => 25$15$:	CALL	CHOCRAQ		; augmente sa vitesse	RET20$:	LOAD	A,STARAQ	TEST	A:0		; raquette droite leve ?	RET,EQ			; non => retour				; oui =>	LOAD	A,CNTRD	OR	A,A		; leve depuis trop longtemps ?	JUMP,NE	15$		; oui => 25$25$:	LOAD	A,VITX	OR	A,A	RET,EQ	DEC	A	JUMP	IVITX31$:	IOF	LOAD	A,CNTIL1	OR	A,A	CALL,EQ	REBIL1	LOAD	A,#FLASH*2	LOAD	CNTIL1,A	ION	LOAD	HL,#B4	CALL	BRUIT	CALL	AFF10	LOAD	HL,#10.		; 10 points	JUMP	35$32$:	IOF	LOAD	A,CNTIL2	OR	A,A	CALL,EQ	REBIL2	LOAD	A,#FLASH*2	LOAD	CNTIL2,A	ION	LOAD	HL,#B4	CALL	BRUIT	CALL	AFF10	LOAD	HL,#10.		; 10 points	JUMP	35$33$:	IOF	LOAD	A,CNTIL3	OR	A,A	CALL,EQ	REBIL3	LOAD	A,#FLASH*2	LOAD	CNTIL3,A	ION	LOAD	HL,#B3	CALL	BRUIT	CALL	AFF20	LOAD	HL,#20.		; 20 points35$:	LOAD	A,STAEFF	OR	A,A	JUMP,SC	36$	LOAD	D,H	LOAD	E,L	LOAD	A,CPXN	LOAD	B,A34$:	ADD	HL,DE		; points X N	DECJ,NE	B,34$36$:	LOAD	A,NOJ	CALL	ADDCNT		; compte qq points	LOAD	A,VITY	ADD	A,#6.	CALL	IVITY	LOAD	A,VITX	ADD	A,#3.	CALL	IVITX	RET40$:	IOF	LOAD	A,CNTTG	OR	A,A	CALL,EQ	REBTG	LOAD	A,#FLASH	LOAD	CNTTG,A	ION	LOAD	A,#-10.	CALL	AVITY	LOAD	A,#+4	CALL	AVITX42$:	LOAD	HL,#B2	CALL	BRUIT	CALL	AFF20	LOAD	A,NOJ	LOAD	HL,#20.	CALL	ADDCNT	RET45$:	IOF	LOAD	A,CNTTD	OR	A,A	CALL,EQ	REBTD	LOAD	A,#FLASH	LOAD	CNTTD,A	ION	LOAD	A,#-6	CALL	AVITY	LOAD	A,#-4	CALL	AVITX	JUMP	42$80$:	LOAD	A,CNTCAN	OR	A,A		; dj un canon ?	RET,NE			; oui => retour	LOAD	HL,#B7	CALL	BRUIT	CALL	REBCAN		; dessine le canon	LOAD	A,#FLASH*5	LOAD	CNTCAN,A	CALL	AFF100	LOAD	A,NOJ	LOAD	HL,#100.	; 100 points	CALL	ADDCNT	LOAD	A,BALX	SUB	A,#10.		; fait un bond en arrire	LOAD	BALX,A	LOAD	A,#-1	LOAD	SENSX,A		; init   gauche <-- droite	LOAD	A,#MAXVX	CALL	IVITX		; init vitesse maximale	RET; Table des zones o il y a dtection sans que la balle ne; touche un obstacle:TZONES:	.B	41.		11.		; cible gauche	.B	48.		16.	.W	10$	.B	35.		114.		; cible droite	.B	42.		120.	.W	20$	.B	11.		43.		; protection A	.B	18.		48.	.W	41$	.B	11.		59.		; protection B	.B	18.		64.	.W	42$	.B	17.		75.		; protection C	.B	24.		80.	.W	43$	.B	75.		0		; sommet flche	.B	80.		10.	.W	50$	.B	75.		120.		; sommet flche	.B	80.		130.	.W	55$	.B	116.		MINX+40.	; trou milieu	.B	120.		MAXX-40.	.W	PERDU	.B	377		; fin de la table10$:	LOAD	HL,#ADCIB112$:	LOAD	A,#SPACE	LOAD	B,(HL)	COMP	A,B		; cible absente ?	RET,EQ			; oui => retour	LOAD	(HL),A		; supprime la cible	LOAD	A,#FLASH*5	LOAD	CNTCIB,A	; arme le compteur	CALL	AFF50	LOAD	A,NOJ	LOAD	HL,#50.	CALL	ADDCNT		; ajoute 50 points	LOAD	HL,#B5	CALL	BRUIT	LOAD	HL,CNTBOU	LOAD	A,L	OR	A,H		; dj un bouchon ?	RET,NE			; oui => retour	CALL	AIDEX		; dessine le bouchon	LOAD	HL,#LGBOUCH	LOAD	CNTBOU,HL	; arme le compteur	LOAD	HL,#ADSTOP	LOAD	(HL),#'S	INC	HL	LOAD	(HL),#'T	INC	HL	LOAD	(HL),#'O	INC	HL	LOAD	(HL),#'P	LOAD	A,STAEFF	COMP	A,#17	RET,NE	LOAD	HL,#ADXN	LOAD	(HL),#'X	INC	HL	INC	HL	LOAD	A,CPXN	INC	A	COMP	A,#9.	JUMP,LO	11$	LOAD	A,#8.11$:	LOAD	CPXN,A	ADD	A,#'1	LOAD	(HL),A	IOF	LOAD	A,STAEFF	SET	A:7	LOAD	STAEFF,A	LOAD	A,CNTIL1	OR	A,A	CALL,EQ REBIL1	LOAD	A,CNTIL2	OR	A,A	CALL,EQ REBIL2	LOAD	A,CNTIL3	OR	A,A	CALL,EQ REBIL3	LOAD	A,#FLASH*2	LOAD	CNTIL1,A	LOAD	CNTIL2,A	LOAD	CNTIL3,A	ION	RET20$:	LOAD	HL,#ADCIB2	JUMP	12$41$:	LOAD	HL,#ADPRO140$:	LOAD	A,(HL)	COMP	A,#SPACE	; lettre existe ?	RET,EQ			; non => retour	LOAD	DE,CNTPRO	LOAD	A,E	OR	A,D		; dj une protection ?	RET,NE			; oui => retour	LOAD	(HL),#SPACE	LOAD	A,NOJ	LOAD	HL,#100.	CALL	ADDCNT		; ajoute 100 points	LOAD	HL,#B10	CALL	BRUIT	CALL	ADDPRO	LOAD	HL,#ADPRO1	LOAD	A,(HL)	COMP	A,#SPACE	RET,NE	LOAD	HL,#ADPRO2	LOAD	A,(HL)	COMP	A,#SPACE	RET,NE	LOAD	HL,#ADPRO3	LOAD	A,(HL)	COMP	A,#SPACE	RET,NE	LOAD	A,#10	LOAD	EXTRA,A	LOAD	HL,#ADEXTRA	LOAD	(HL),#'E	INC	HL	LOAD	(HL),#'X	INC	HL	LOAD	(HL),#'T	INC	HL	LOAD	(HL),#'R	INC	HL	LOAD	(HL),#'A	INC	HL	INC	HL	LOAD	(HL),#'B	INC	HL	LOAD	(HL),#'A	INC	HL	LOAD	(HL),#'L	INC	HL	LOAD	(HL),#'L	INC	HL	LOAD	(HL),#'E	RET			; EXTRA BALL42$:	LOAD	HL,#ADPRO2	JUMP	40$43$:	LOAD	HL,#ADPRO3	JUMP	40$50$:	LOAD	HL,CNTPRO	LOAD	A,L	OR	A,H	RET,EQ	LOAD	A,#70.	LOAD	BALY,A	LOAD	A,#+1	LOAD	SENSX,A	LOAD	A,#-1	LOAD	SENSY,A	LOAD	A,#3	CALL	IVITX	LOAD	A,#4	CALL	IVITY	LOAD	A,NOJ	LOAD	HL,#100.	CALL	ADDCNT		; ajoute 100 points	LOAD	HL,#B11	CALL	BRUIT	CALL	MPROG	LOAD	A,#FLASH*2	LOAD	CNTPRG,A	RET55$:	LOAD	HL,CNTPRO	LOAD	A,L	OR	A,H	RET,EQ	LOAD	A,#70.	LOAD	BALY,A	LOAD	A,#-1	LOAD	SENSX,A	LOAD	A,#-1	LOAD	SENSY,A	LOAD	A,#3	CALL	IVITX	LOAD	A,#4	CALL	IVITY	LOAD	A,NOJ	LOAD	HL,#100.	CALL	ADDCNT		; ajoute 100 points	LOAD	HL,#B11	CALL	BRUIT	CALL	MPROD	LOAD	A,#FLASH*2	LOAD	CNTPRD,A	RET; Gestion de la vitesse:; ----------------------;--------\; AVITX   >;========/; Augmente ou diminue une vitesse en (X).; in	A	valeur  ajouter en complment  deux; out	VITX;	MDELX; mod	-AVITX:	PUSH	AF	PUSH	BC	LOAD	B,A	LOAD	A,SENSX	LOAD	C,A		; C  <-- sens de la vitesse	LOAD	A,VITX	TEST	C:7	JUMP,EQ	10$	NEG	A		; A  <-- vitesse en cpl  210$:	ADD	A,B		; augmente ou diminue	LOAD	B,A		; B  <-- nouvelle vit (cpl  2)	LOAD	A,#1	TEST	B:7	JUMP,EQ	40$	LOAD	A,B	NEG	A	LOAD	B,A		; B  <-- valeur absolue vitesse	LOAD	A,#-140$:	LOAD	SENSX,A		; init nouveau sens (+/-)	LOAD	A,B	CALL	IVITX		; init nouvelle vitesse	POP	BC	POP	AF	RET;--------\; AVITY   >;========/; Augmente ou diminue une vitesse en (Y).; in	A	valeur  ajouter en complment  deux; out	VITY;	MDELY; mod	-AVITY:	PUSH	AF	PUSH	BC	LOAD	B,A	LOAD	A,SENSY	LOAD	C,A		; C  <-- sens de la vitesse	LOAD	A,VITY	TEST	C:7	JUMP,EQ	10$	NEG	A		; A  <-- vitesse en cpl  210$:	ADD	A,B		; augmente ou diminue	LOAD	B,A		; B  <-- nouvelle vit (cpl  2)	LOAD	A,#1	TEST	B:7	JUMP,EQ	40$	LOAD	A,B	NEG	A	LOAD	B,A		; B  <-- valeur absolue vitesse	LOAD	A,#-140$:	LOAD	SENSY,A		; init nouveau sens (+/-)	LOAD	A,B	CALL	IVITY		; init nouvelle vitesse	POP	BC	POP	AF	RET;--------\; IVITX   >;========/; Initialise la vitesse en X sans changer le sens.; in	A	vitesse (0..7); out	VITX;	MDELX; mod	-IVITX:	PUSH	AF	PUSH	DE	PUSH	HL	COMP	A,#MAXVX+1	JUMP,LO	10$	LOAD	A,#MAXVX10$:	LOAD	VITX,A	LOAD	DE,#VITESSE	LOAD	L,A	LOAD	H,#0	ADD	HL,HL	ADD	HL,DE	LOAD	A,(HL)	INC	HL	LOAD	H,(HL)	LOAD	L,A	LOAD	MDELX,HL	LOAD	HL,#1	LOAD	DELX,HL	POP	HL	POP	DE	POP	AF	RET;--------\; IVITY   >;========/; Initialise la vitesse en Y sans changer le sens.; in	A	vitesse (0..7); out	VITY;	MDELY; mod	-IVITY:	PUSH	AF	PUSH	DE	PUSH	HL	COMP	A,#MAXVY+1	JUMP,LO	10$	LOAD	A,#MAXVY10$:	LOAD	VITY,A	LOAD	DE,#VITESSE	LOAD	L,A	LOAD	H,#0	ADD	HL,HL	ADD	HL,DE	LOAD	A,(HL)	INC	HL	LOAD	H,(HL)	LOAD	L,A	LOAD	MDELY,HL	LOAD	HL,#1	LOAD	DELY,HL	POP	HL	POP	DE	POP	AF	RETVITESSE:	.W	800.		; 0	.W	400.		; 1	.W	200.		; 2	.W	100.		; 3	.W	50.		; 4	.W	20.		; 5	.W	10.		; 6	.W	5.		; 7	.W	4.		; 8	.W	3.		; 9	.W	3.		; 10	.W	2.		; 11; Gestion des raquettes:; ----------------------;--------\; INIRAQ  >;========/; Initialise les raquettes.; in	-; out	STARAQ	zro; mod	toutINIRAQ:	LOAD	HL,#RAQGB	LOAD	DE,#COORRG	CALL	DESMOT	LOAD	HL,#RAQDB	LOAD	DE,#COORRD	CALL	DESMOT	XOR	A,A	LOAD	STARAQ,A	; init status raquettes	LOAD	FONC,A		; pas de touches fonctions	RET;--------\; BOURAQ  >;========/; Bouge les raquettes en fonction de FONC.; in	FONC; out	-; mod	toutBOURAQ:	LOAD	HL,#CNTRG	LOAD	A,(HL)	OR	A,A	JUMP,EQ 02$	DEC	(HL)02$:	LOAD	HL,#CNTRD	LOAD	A,(HL)	OR	A,A	JUMP,EQ 04$	DEC	(HL)04$:	LOAD	A,STARAQ	LOAD	C,A		; C  <-- STARAQ	LOAD	D