D	H,(IX)+5	; HL <-- adresse ds l'cran	TEST	(IX)+6:1	; re-init ?	JUMP,NE	50$		; oui => 50$	SET	(IX)+6:2	; signal compteur  jour	PUSH	HL	LOAD	L,(IX)+0	LOAD	H,(IX)+1	LOAD	E,(IX)+2	LOAD	D,(IX)+3	OR	A,A	SUBC	HL,DE		; compteur  jour ?	POP	HL	JUMP,EQ	80$		; oui => 80$	CLR	(IX)+6:2	; signal compteur pas  jour20$:	LOAD	A,(HL)	INC	A		; inc dans l'cran !	COMP	A,#'9+1	JUMP,LO	30$	LOAD	(HL),#'0	DEC	HL	JUMP	20$30$:	LOAD	(HL),A	LOAD	L,(IX)+0	LOAD	H,(IX)+1	INC	HL	LOAD	(IX)+0,L	LOAD	(IX)+1,H	CALL	GRATIS	JUMP	80$50$:	CLR	(IX)+6:1	; il est re-initialis	SET	(IX)+6:2	; et aussi  jour	LOAD	C,#660$:	LOAD	(HL),#'0	DEC	HL	DEC	C	JUMP,NE	60$	LOAD	(IX)+0,#0	LOAD	(IX)+1,#0	LOAD	(IX)+2,#0	LOAD	(IX)+3,#0	LOAD	(IX)+7,#080$:	LOAD	DE,#8.	ADD	IX,DE		; IX <-- ^compteur suivant	DEC	B	JUMP,NE	10$	RET;--------\; GETCNT  >;--------/; in	A	numro du compteur; out	IX	^table du compteur; mod	AF,IXGETCNT:	PUSH	DE	PUSH	HL	LOAD	L,A	LOAD	H,#0	LOAD	DE,#TACNT	ADD	HL,HL	ADD	HL,HL	ADD	HL,HL	ADD	HL,DE	PUSH	HL	POP	IX	POP	HL	POP	DE	RET;--------\; GRATIS  >;========/; Test et donne les parties gratuites; in	HL points actuels;	IX pointeur table des points; out	-; mod	AF,C,DE,HLGRATIS:	PUSH	HL	LOAD	HL,#LGRATI	LOAD	DE,#IGRATI	LOAD	A,(IX)+7	LOAD	C,A	OR	A,A	JUMP,EQ 32$31$:	ADD	HL,DE	DEC	A	JUMP,NE	31$32$:	EX	HL,DE	POP	HL	OR	A,A	SUBC	HL,DE	RET,LO	INC	C	LOAD	(IX)+7,CDOGRAT:	LOAD	A,PARTIE	INC	A	LOAD	PARTIE,A	LOAD	HL,#SALPHA+NCAR*17.+57.10$:	LOAD	A,(HL)	INC	A		; inc dans l'cran !	COMP	A,#'9+1	JUMP,LO	20$	LOAD	(HL),#'0	DEC	HL	JUMP	10$20$:	LOAD	(HL),A	LOAD	HL,#B12	PUSH	BC	CALL	BRUIT	POP	BC	RET;--------\; LOTERI  >;========/LOTERI:	LOAD	A,R	AND	A,#37	LOAD	LOTNO,A	LOAD	HL,#LOTER1	LOAD	DE,#ORLOT	CALL	DESMOT	LOAD	HL,#LOTER2	LOAD	DE,#ORLOT+16.	CALL	DESMOT	LOAD	HL,#TXLOT	.W	?SETCURS,?TEXTIM	.ASCIZ	/LOTERIE/	LOAD	A,#35	.W	?BEEP	.W	?DELAY,1000.	LOAD	HL,#1.	LOAD	C,#-11